var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"지식<color=#ff3636>의 성찬</color>이 준비되었<color=#ff3636>다. 연회가</color> 시작<b>되</b>었다.","JPN":"知識<color=#ff3636>の聖餐</color>の準備が整っ<color=#ff3636>た。宴会が</color> 始ま<b>っ</b>た。","ENG":"The fe<color=#ff3636>ast of know</color>ledge has be<color=#ff3636>en prepared. The banquet</color> has st<b>arte</b>d.","TWN":"知識的<color=#ff3636>盛宴</color>準備好了。<color=#ff3636>宴會</color>開始<b>了</b>。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"제길, 이런 곳에 아직도 잔해가 남아있다니!","JPN":"くそ、こんなところにまだ残骸がある！","ENG":"Dammit, there are still Remains in a place like this!","TWN":"見鬼，這地方竟還殘留著殘骸！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"모두 특수탄을 아끼지 마! 남김없이 때려 박아!","JPN":"皆、特殊弾を惜しむな！　全部ぶち込め！","ENG":"Don't conserve your special bullets! Shoot every last one of them!","TWN":"大家不要省著特殊彈頭！給我盡情地用！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"대장님! 뭔가 이상합니다.","JPN":"隊長！　何かおかしいです。","ENG":"Commander! Something's off.","TWN":"隊長！有點不對勁。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L21_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"잔해가 저희 공격을 무시하고 어디론가 향하고 있습니다.","JPN":"残骸が私たちの攻撃を無視してどこかに向かっています。","ENG":"The Remains are ignoring our attacks and heading somewhere.","TWN":"殘骸無視我們的攻擊，正朝著某個地方前進。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"何だって？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"고준위 침식파 감지! 대장님, 뭔가 옵니다!","JPN":"高レベルの侵食波を感知！　隊長、何かが来ます！","ENG":"Detecting high-level Corruption ray! Commander, something's approaching us!","TWN":"檢測到了高危險級侵蝕波！隊長，有東西在靠近！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"이런……! 다들 전투 대기!","JPN":"くっ……！　皆、戦闘待機だ！","ENG":"Not good...! Everyone, prepare for battle!","TWN":"糟了……！大家準備戰鬥！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"즉시 기관장님께 연락해!","JPN":"直ちに機関長に連絡しろ！","ENG":"Contact the Chief, NOW!","TWN":"馬上聯繫機關長！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"카운터 요원이 올 때까지는 이 자리를 사수해야 한다!","JPN":"カウンターのエージェントが来るまで、この場を離れるな！","ENG":"We need to hold this place down until a Counter agent arrives!","TWN":"要在制裁者來之前守住這個位置！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"어머나, 제 아이들이 아직 남아있었네요?","JPN":"あら、まだ私の子どもたちが残っていましたね。","ENG":"Oh, dear. I see some of my babies still remain.","TWN":"哎呀，還有留下一點我的孩子呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"적성 개체 발견! 쏴라!","JPN":"敵性個体を発見！　撃て！","ENG":"Hostile found! Shoot!","TWN":"發現敵人個體！開槍！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"너무하세요. 전 아무 짓도 안 했는데.","JPN":"ひどいです。私は何もしてないのに。","ENG":"That seems unfair. I didn't even do anything.","TWN":"太過分了，我可什麼都沒做。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"그냥 아이들을 회수하러 온 것뿐이라고요?","JPN":"私はただ、子どもたちを回収しに来ただけですよ？","ENG":"I'm just here to pick up my babies.","TWN":"我只是來收回我的孩子而已。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"아이들이라고?","JPN":"子どもたちだと？","ENG":"Babies?","TWN":"孩子？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"지식<color=#ff3636>의 성찬</color>이 준비되었<color=#ff3636>다. 연회가</color> 시작<b>되</b>었다.","JPN":"知識<color=#ff3636>の聖餐</color>の準備が整っ<color=#ff3636>た。宴会が</color> 始ま<b>っ</b>た。","ENG":"The fe<color=#ff3636>ast of know</color>ledge has be<color=#ff3636>en prepared. The banquet</color> has st<b>arte</b>d.","TWN":"知識的<color=#ff3636>盛宴</color>準備好了。<color=#ff3636>宴會</color>開始<b>了</b>。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L43_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"옳지, 옳지~ 저 아저씨들이 무섭게 했구나?","JPN":"よし、よし～あのおじさんたち怖かったよね？","ENG":"There, there. Those big men scared you, huh?","TWN":"乖～乖～是那些大叔讓你害怕了？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"자, 그럼 이제 엄마 품에 안겨 볼까?","JPN":"さあ、お母さんが抱っこしてあげるからね。","ENG":"Now, come into my embrace.","TWN":"好，來投入母親的懷抱吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"이런 미친……! ","JPN":"そんなバカな……！ ","ENG":"What the...!","TWN":"你這個瘋子……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"설마 잔해를 잡아먹은 건가……?","JPN":"まさか、残骸を食ったのか……？","ENG":"Did she just devour the Remains...?","TWN":"竟然把殘骸吃下去了……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"뭘 머뭇거리고 있어! 계속 쏴 버려!","JPN":"何を尻込みしている！　撃ち続けろ！","ENG":"What are you waiting for?! Just shoot!","TWN":"猶豫什麼！繼續開槍！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"잡아먹다니요, 숙녀한테 그런 말을 하다니 실례잖아요.","JPN":"食うとか、レディーに対して失礼な言い方をしますね。","ENG":"Devour? How rude to say to a lady.","TWN":"怎麼能說是吃呢，對淑女說那種話，真是太失禮了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"저희는 그저 호수의 본질에 충실할 뿐이랍니다?","JPN":"我々はただ、湖の本質に忠実なだけですよ。","ENG":"We are merely true to the nature of the Lake.","TWN":"我們只是忠實於湖水的本質而已？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BLASTER_ATTACK"},{"id":"L9_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"간신히 현계할 수 있는 몸을 얻은 참이라, 더 많은 아이들의 힘이 필요하거든요.","JPN":"顕現できる肉体を手に入れたばかりで、もっとたくさんの子どもたちの力が必要なんです。","ENG":"I've only just acquired a form in reality, so I need the power of more babies.","TWN":"好不容易才得到了能維持現狀的身體，所以需要更多的孩子的力量。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"그러니까 아저씨들도…….","JPN":"だからおじさんたちも……","ENG":"So will you...","TWN":"所以叔叔們……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"<color=#ff3636>저희와 하나가 되어주시겠어요?</color>","JPN":"<color=#ff3636>我々と一つになってくれませんか？</color>","ENG":"<color=#ff3636>become one with us?</color>","TWN":"<color=#ff3636>也和我們合而為一吧？</color>"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_MINI_MOVE_ATTACK"},{"id":"L13_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"히, 히이익……?","JPN":"ひ、ひいいっ……！","ENG":"E-eeek...?","TWN":"咿，咿……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"으음? 이 말뚝은?","JPN":"うん？　この杭は……？","ENG":"Hmm? This stake is?","TWN":"嗯？這個鐵釘是？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_METAL"},{"id":"L18_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"와아, 우리 에델이랑 비슷하면서도 뭔가 다른데?","JPN":"わあ、うちのエデルと似てるけど、なんか違うね。","ENG":"Wow, you're similar but different to our Edel.","TWN":"哇，感覺和我們艾瑟兒差不多，但又有點不一樣？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L19_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"오, 리벳이로군요!","JPN":"ああ、リベットですね！","ENG":"Oh, Rivet!","TWN":"喔，是里維！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"이 몸으로는 처음이네요? 반가워요, 리벳.","JPN":"この体で会うのは初めてですね。会えてうれしいです、リベット。","ENG":"This is the first time greeting you in this form. Nice to see you, Rivet.","TWN":"第一次用這個身體和你相遇呢？很高興見到你呀，里維～"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"나도 반가워~ 에델 주니어!","JPN":"アタシも～エデルジュニアさん！","ENG":"Nice to see you too, Edel Junior!","TWN":"我也很高興見到你～小艾瑟兒！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"먼저 쏴버리다니! 제정신인가요!?","JPN":"先に撃つなんて正気ですか！","ENG":"You just shot first?! Are you insane?!","TWN":"竟然先開槍！你瘋了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"분명 기습할 기회는 한 번밖에 없을 거라고, 누차 부탁드리지 않았습니까!","JPN":"奇襲のチャンスは一回しかないと、何回も申し上げたじゃないですか！","ENG":"I have told you repeatedly that there would only be one opportunity to ambush it!","TWN":"我三番二次地拜託你了，偷襲的機會只有一次！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그치만 이건 내 잘못이 아닌걸?","JPN":"でもアタシは悪くないよ？","ENG":"But this isn't my fault, though.","TWN":"但這不是我的錯啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"저걸 보니까 손가락이 근질근질한 걸, 어떻게 가만히 있으라는 거야?","JPN":"あれをみたら指がうずいて仕方なかったんだもん。じっとしていられないよ。","ENG":"How am I supposed to keep still when my fingers start tingling as soon as I see that?","TWN":"看到那個東西，我的手指頭都癢了，不能坐視不理啊！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"심의회 집행사제님이랑…… 바니걸?","JPN":"審議会の執行司祭様と……バニーガール？","ENG":"The Inquisitorial Priest of the Council, and... a bunny girl?","TWN":"議會執行祭司……和兔子女？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"멍청아! 레지나 맥크레디의 오른팔이잖아! 작전 브리핑에서 뭘 본거야!","JPN":"バカ！　レジーナ・マクレディーの右腕じゃないか！　作戦ブリーフィングの時何を聞いてたんだ！","ENG":"You idiot! It's Regina MacCready's right-hand woman! Were you paying attention during the mission briefing?!","TWN":"笨蛋！那是蕾佳娜·麥克蕾蒂的心腹！作戰會議的時候你沒看到嗎！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기관원분들은 지원사격을 부탁드리겠습니다.","JPN":"機関員の皆さまには、援護射撃をお願いします。","ENG":"I ask the Institution members to provide support fire.","TWN":"請求機關成員進行支援射擊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"카운터 혼자서 대응할 수 있는 상대가 아니에요.","JPN":"カウンター一人で太刀打ちできる相手ではありません。","ENG":"One Counter cannot deal with this enemy alone.","TWN":"那不是僅憑一個制裁者就能對付的對手。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"엄마 손님이니까 조용히 해, 판.","JPN":"お母さんのお客さんだから大人しくしなさい、パン。","ENG":"Mommy has guests, so be quiet, Pan.","TWN":"噓，這些是母親的客人，安靜點，潘。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"이브의 탄생을 축하해 주실 분들이 이렇게나 많이 오셨군요?","JPN":"イヴの誕生を祝ってくれる方々がこんなにもたくさん集まってくださるなんて！","ENG":"I see there are so many guests here to celebrate Eve's birth!","TWN":"這麼多人來這裡，都是為了祝賀伊芙誕生嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"이브는 너무 기뻐요!","JPN":"イヴ、とても嬉しいです！","ENG":"Eve is so happy!","TWN":"伊芙太高興了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"여러분들한테서는 어떤 각별한 기억을 맛볼 수 있을까요?","JPN":"皆さんからはどんな格別な記憶が味わえるでしょう？","ENG":"What kind of special memories will I be able to taste from you all?","TWN":"從大家身上可以感受到什麼特別的記憶呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L44_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"좋아하는 영화는 뭔가요? 싫어하는 음식은?","JPN":"好きな映画は何ですか？　嫌いな食べ物は？","ENG":"What is your favorite movie? What food do you dislike?","TWN":"喜歡的電影是什麼？討厭的食物呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"무엇과도 바꿀 수 없는 소중한 사람이 있으신가요? 혹시 그 사람을 잃어본 경험은?","JPN":"何にも代えられない大切な人がいますか？　そんな人を失った経験は？","ENG":"Is there a loved one that cannot be replaced? Any experience of losing them?","TWN":"有什麼不能用任何東西交換的珍貴之人嗎？你有失去過那個人的經歷嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"아! 직접 죽여본 경험도 있으신가요? 그럼 좋겠다!","JPN":"あ！　自分の手で殺した経験はありますか！　あったらいいなぁ！","ENG":"Ah! Have you ever killed them yourselves? That would be great!","TWN":"啊！你親手把他給殺了？那太好了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"수녀님, 손이 떨리고 있잖아, 괜찮아?","JPN":"シスター、手が震えてるよ。大丈夫？","ENG":"Sister, your hands are shaking. Are you all right?","TWN":"修女，你的手在發抖，你沒事吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"헛소리하지 말고 싸울 준비나 하세요. 추종자.","JPN":"くだらないこと言わないで、戦う準備をしてください。取り巻き。","ENG":"Quit the chitchat and get ready to fight, Follower.","TWN":"別胡說八道了，準備戰鬥吧，追隨者。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"저걸 현실로 끌고 갔다간…… 우리 세계는 지옥도가 펼쳐질 겁니다.","JPN":"あれを現実に行かせてしまったら……世界は地獄と化してしまいます。","ENG":"If we drag that thing back to the Normalside... our world will descend into the pits of hell.","TWN":"如果讓它到現實……那我們的世界將成為人間地獄。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"자, 그럼 먹기 좋게 한 자리에 모여주신 분들에 대한 예의도 있으니까.","JPN":"さあ、食べやすいように集まってくだった皆さんにも申し訳ありませんし……","ENG":"Now, seeing how you all went through the trouble of gathering here to make it easier for me to devour you all,","TWN":"好了，大家聚在一起，方便我一次吃掉，我還是要講禮貌的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_03"},{"id":"L6_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"성찬을 남기면 안 되겠죠?","JPN":"聖餐を食べ残しちゃだめですよね。","ENG":"I shall make sure to finish every last piece of this feast.","TWN":"盛宴要吃完喔？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"으음?","JPN":"うん？","ENG":"Mm?","TWN":"呃嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_45"},{"id":"L10_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"어라? 몸을 움직일 수가 없네요?","JPN":"あれ、身動きがとれませんね。","ENG":"Huh? I can't move my body.","TWN":"啊？身體動不了了？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"모두 내 뒤로 물러서!","JPN":"皆、俺の後ろに下がれ！","ENG":"Everyone, get behind me!","TWN":"都給我退到我身後！"},"stage":{"bg":"PRYDWEN_05","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"지금이야! 홍차 폭탄!","JPN":"今だ、紅茶爆弾！","ENG":"Now! Tea Bomb!","TWN":"就是現在！紅茶炸彈！"},"stage":{"bg":"PRYDWEN_05","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"저한테 이래라저래라 명령하다니……!","JPN":"私に命令するなんて……！","ENG":"How dare you order me around...!","TWN":"你竟敢命令我……！"},"stage":{"bg":"PRYDWEN_05","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"건방져졌군요, 물벼룩!","JPN":"ずいぶんと生意気になりましたわね、ミジンコ！","ENG":"How insolent, Water Flea!","TWN":"未免也太放肆了，水蚤！"},"stage":{"bg":"PRYDWEN_05","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 나이스 캐치였어요. 칭찬해 드리죠.","JPN":"でも、ナイスキャッチでした。褒めてあげますわ。","ENG":"But it was a good catch. I'll give you that.","TWN":"但時機正好，值得稱讚。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"바로 준비해.","JPN":"次に備えろ。","ENG":"Get ready.","TWN":"保持警惕。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L25_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"이렇게 시시하게 끝날 리가 없어.","JPN":"こんなに簡単に終わるわけがない。","ENG":"This won't end that easily.","TWN":"不可能就這麼輕易結束。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"호오, 팬드래건 기관장님까지 오셨군요.","JPN":"ほお、ペンドラゴン機関長まで。","ENG":"Ho-oh. Chief Pendragon is here as well.","TWN":"喔，連潘德拉貢機關長都來了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"어머니의 안에서 봤을 때보다, 훨씬 몸짓이 우아하세요.","JPN":"お母さんの中で見ていた時よりも優雅な身のこなしですね。","ENG":"Your movements are far more elegant than when I was watching you from inside Mother.","TWN":"比在母親的身體裡看時，身姿要優雅許多。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"이브도 기관장님처럼 우아하게 춤 출 수 있으면 좋을 텐데…….","JPN":"イヴも機関長みたいに優雅な踊りができればいいのに……","ENG":"Eve also wishes to be able to dance so gracefully like you, Chief...","TWN":"要是伊芙也能像機關長一樣優雅地跳舞就好了……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"입 발린 소리는 거기까지 하시죠. 괴물.","JPN":"心にもない言葉はそこまでですよ、化け物。","ENG":"You can stop those meaningless compliments. Monster.","TWN":"別再說那些花言巧語了，怪物。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당신에게 우아하다는 소리를 들어봤자, 불쾌할 뿐이니까요.","JPN":"あなたに優雅だのなんだの言われても、不愉快ですわ。","ENG":"It's only revolting to hear those words come out of your mouth.","TWN":"就算聽到你的誇讚，也只會讓我不快。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"힝, 진짠데…….","JPN":"ひいん、本当なのに……","ENG":"Hng... I'm not lying, though...","TWN":"嗚，我說的是真的……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"버넷 요원, 무사하셨군요.","JPN":"エージェント・バーネット、無事でしたね。","ENG":"Agent Burnett, you are safe.","TWN":"伯內特，你沒事就好。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"한껏 폼내고 왔잖아? 뭔가 많이 달라졌는데, 로이 버넷?","JPN":"すごいカッコつけてんじゃん。なんかずいぶん変わったね、ロイ・バーネット。","ENG":"You've dolled up! You seem very different, Roy Burnett.","TWN":"怎麼打扮得這麼帥氣啦？你變了很多呢，羅伊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"다들, 티 타임은 나중에 갖도록 해요.","JPN":"皆さん、ティータイムは後にしましょう。","ENG":"Tea time can wait.","TWN":"閒聊還是等以後吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"저건 마왕의 위계를 일부나마 물려받은 신성 침식체.","JPN":"あれは魔王の位階の一部を受け継いでいる、神聖侵食体。","ENG":"That is a Divine Corrupted Object that partially succeeded the Demon Lord's role.","TWN":"那是繼承了部分魔王位階的神聖侵蝕體。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그릇이 된 육신이 아직 그 힘에 완전히 적응하지 못한 지금이 유일한 기회예요.","JPN":"器となっている肉体がまだ力に適応しきってない今がチャンスです。","ENG":"The body that became the vessel still hasn't completely adapted to the power. Now's our only chance.","TWN":"成為器皿的肉體還沒有完全適應那股力量，所以現在是唯一的機會。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관장이 명합니다! 봉쇄하세요, 물벼룩!","JPN":"機関長の名により命じます！　封鎖しなさい、ミジンコ！","ENG":"This is an order from the Chief! Seal it, Water Flea!","TWN":"這是機關長的命令！封鎖起來，水蚤！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"나 참. 그 물벼룩 소리 좀 그만 하면 어디가 덧나냐?","JPN":"ったく、そのミジンコ呼び、そろそろやめたらどうだ？","ENG":"Blimey. Does it hurt you to stop calling me Water Flea?","TWN":"真是的，少說二句水蚤會死嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"거기까지다……!","JPN":"そこまでだ……！","ENG":"I don't think so...!","TWN":"到此為止了……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"제길, 가아그셰블라를 봉쇄한 사슬을 단숨에 끊어버리다니……!","JPN":"くそ、ガアグシェブラを封じた鎖を一気に断ち切るとは……！","ENG":"Bollocks, he instantly cut the chain that sealed Gha'agsheblah...!","TWN":"可惡，居然一口氣就把封鎖加格舍夫拉的鐵鍊給切斷了……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"아직 포기하긴 일러요!","JPN":"まだ諦めてはなりません！","ENG":"We cannot give up yet!","TWN":"現在放棄還為時過早！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"알고 있다고!","JPN":"わかってるって！","ENG":"I know!","TWN":"我知道！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"잠시 뒤로 물러서시죠, 어머니.","JPN":"お母さん、後ろに下がっていてください。","ENG":"We need to step back, Mother.","TWN":"請往後退一點，母親。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"아무리 급조했다고 해도, 봉인 사슬에 닿으면 위험합니다.","JPN":"急ごしらえの体では、封印の鎖に触れると危険です。","ENG":"It was created in a hurry, but the Sealing Chain is still dangerous to the touch.","TWN":"即使是新的鐵鍊，但碰到還是很危險。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"와아, 기사님께서 절 걱정해 주시다니……!","JPN":"わあ、騎士様が私を気にかけてくださるなんて……！","ENG":"Oh, my. My dear knight is worried about me...!","TWN":"哇，騎士竟然擔心我……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"이브는 정말 기뻐요!","JPN":"イヴはとても嬉しいです！","ENG":"Eve is so happy!","TWN":"伊芙真的很高興！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"이제 봉인 사슬 같은 건 얼마든지 만들어 낼 수 있어!","JPN":"封印の鎖なんか、いくらでも生み出せる！","ENG":"I can make however many Sealing Chains I want now!","TWN":"封印鎖鏈什麼的，我現在完全可以隨時製造出來！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_32"},{"id":"L25_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"이걸로 끝이라고 생각하지 마!","JPN":"これで終わりだと思うな！","ENG":"This isn't over!","TWN":"別以為這就完了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"어떤 전설이든, 그 시작은 자네처럼 허세로 시작해.","JPN":"どんな伝説も、最初は君みたいな見栄っ張りから始まる。","ENG":"All legends start with someone's bluff, like you.","TWN":"不管是多偉大的傳說，最開始都是像你一樣的虛張聲勢。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 그 허세를 끝까지 포기하지 않고 결국 진실로 만들어낸다면.","JPN":"だが最後まで諦めずそれを本物にしてみせた時。","ENG":"But if you can keep up with the bluff and ultimately make it a reality,","TWN":"但是，如果你到最後也不放棄那個態度，最終使其成為真實的話。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그제서야 전설은 생명력을 얻고, 사람들의 기억 속에 영원토록 새겨지게 되지.","JPN":"伝説には命が宿り、人々の記憶にも永遠に刻まれるようになる。","ENG":"the legend gains power, and it is forever engraved in the memories of the people.","TWN":"這樣，傳說就會獲得生命力，並永遠銘刻在人們的記憶中。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까 버넷은 절대 꺾이면 안 돼.","JPN":"だから、バーネットは屈してはならない。","ENG":"So, a Burnett should never break.","TWN":"所以，伯內特，絕對不能屈服啊。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그 전설을 쫓는 이들이 다시금 허세를 부리고, 그 허세가 새로운 전설이 될 때까지 말이야.","JPN":"その伝説を追う者たちがまた見栄を張り、再び新たな伝説が生まれるまでにな。","ENG":"Until the ones who chase after that legend bluff, and the bluff becomes a new legend.","TWN":"直到追逐傳說的人重新虛張聲勢，而那個虛張聲勢又成為新的傳說。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 이제는…… 자네가 그 전설을 이을 차례야.","JPN":"そして今は……君がその伝説を継ぐ番だ。","ENG":"And now... it's your turn to carry on the legend.","TWN":"現在……該由你去繼承那個傳說了。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"로이 버넷.","JPN":"ロイ・バーネット。","ENG":"Roy Burnett.","TWN":"羅伊·伯內特。"},"stage":{"bg":"PRYDWEN_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"내 워치가, 내 영혼이 여기서 박살나는 한이 있더라도……!","JPN":"俺のウォッチが、俺の魂がここで砕け散ることになっても……！","ENG":"Even if my Watch, my soul is destroyed here...!","TWN":"即使我的能量環，我的靈魂在這裡粉碎……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L37_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"네놈들을…… 반드시 봉인하겠어!","JPN":"貴様らを……必ず封印してやる！","ENG":"I will still... seal you, no matter what!","TWN":"我也一定要……封印你們這些傢伙！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"가아그셰블라의 안에 있는 그 아이를…… 구해내겠어!!","JPN":"ガアグシェブラの中にいるあの子を……救い出してみせる！","ENG":"I will... save the child inside Gha'agsheblah!!","TWN":"我要救出……在加格舍夫拉裡面的那個孩子！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};